USE OffshoreShiftRosterDB;
GO

IF OBJECT_ID('CCL Offshore Team Shift Roaster', 'U') IS NOT NULL
    DROP TABLE [CCL Offshore Team Shift Roaster];
GO

CREATE TABLE [CCL Offshore Team Shift Roaster] (
    [Date] DATE PRIMARY KEY,
    [Day] VARCHAR(50) NOT NULL,
    [4AM - 1PM           After Business hours] NVARCHAR(500) NULL,
    [1:00 PM - 10:00 PM   Production ] NVARCHAR(500) NULL,
    [7:00PM - 4:00AM Business hours] NVARCHAR(500) NULL,
    [Week off] NVARCHAR(500) NULL,
    [Comments] NVARCHAR(1000) NULL
);
GO


